-- Table structure for table `transactions`
--

DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transactions` (
  `transaction_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT (uuid()),
  `from_account_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `to_account_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `amount` decimal(18,2) NOT NULL,
  `idempotency_key` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime NOT NULL DEFAULT (utc_timestamp()),
  PRIMARY KEY (`transaction_id`),
  UNIQUE KEY `idempotency_key` (`idempotency_key`),
  KEY `idx_txn_from` (`from_account_id`),
  KEY `idx_txn_to` (`to_account_id`),
  KEY `idx_txn_idem` (`idempotency_key`),
  CONSTRAINT `transactions_ibfk_1` FOREIGN KEY (`from_account_id`) REFERENCES `accounts` (`account_id`) ON DELETE RESTRICT,
  CONSTRAINT `transactions_ibfk_2` FOREIGN KEY (`to_account_id`) REFERENCES `accounts` (`account_id`) ON DELETE RESTRICT,
  CONSTRAINT `chk_txn_amount` CHECK ((`amount` > 0)),
  CONSTRAINT `chk_txn_diff_accts` CHECK ((`from_account_id` <> `to_account_id`))
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

